(()=>{'use strict';
const URL0='https://saodmeoilixfdqentofp.supabase.co';
const BUCKET='doit-files';
const $=s=>document.querySelector(s);
const T=v=>String(v??'').trim();
const TEAM=[
  {key:'thakoon',input:'#teamThakoonFile',preview:'#teamThakoonPreview',name:'นาย ฐากูร อุปมัย',code:'DSHFSAYA',role:'ผู้ควบคุมงาน/หัวหน้าสั่งการ',path:'team/team-thakoon.jpg'},
  {key:'atthawit',input:'#teamAtthawitFile',preview:'#teamAtthawitPreview',name:'นาย อรรถวิทย์ ชัยชะนะ',code:'AYAADS01',role:'ที่ปรึกษา/แอดมิน',path:'team/team-atthawit.jpg'},
  {key:'chatchai',input:'#teamChatchaiFile',preview:'#teamChatchaiPreview',name:'นาย ฉัตรชัย จันทร์กลิ่น',code:'AYAPS062',role:'ผู้สร้าง/จัดทำ',path:'team/team-chatchai.jpg'}
];
const QR_PATH='team/dev-qr.png';
const QR_CONFIG_PATH='team/dev-qr-config.json';
function cfg(){let c={};try{c=JSON.parse(localStorage.getItem('doit-cloud-cfg')||'{}')}catch{}let u=T($('#sbUrl')?.value||c.url).replace(/\/$/,'')||URL0;let k=T($('#sbKey')?.value||c.key);return{u,k}}
function H(c,x={}){return{apikey:c.k,authorization:'Bearer '+c.k,...x}}
function status(s,ok=false){const el=$('#teamPhotoStatus');if(el)el.innerHTML='<div class="'+(ok?'ok':'warn')+'">'+s+'</div>';console.log('[TEAM PHOTO]',s)}
function qrStatus(s,ok=false){const el=$('#devQrStatus');if(el)el.innerHTML='<div class="'+(ok?'ok':'warn')+'">'+s+'</div>';console.log('[DEV QR]',s)}
function publicUrl(c,path){return `${c.u}/storage/v1/object/public/${BUCKET}/${path}`}
async function put(c,path,blob,type){const url=`${c.u}/storage/v1/object/${BUCKET}/${encodeURIComponent(path).replace(/%2F/g,'/')}`;const r=await fetch(url,{method:'POST',headers:H(c,{'Content-Type':type,'x-upsert':'true'}),body:blob});const t=await r.text();if(!r.ok)throw Error(t||r.status);return t}
function fileToImage(file){return new Promise((res,rej)=>{const img=new Image();img.onload=()=>res(img);img.onerror=()=>rej(Error('อ่านรูปไม่ได้: '+file.name));img.src=URL.createObjectURL(file)})}
function blobToDataUrl(blob){return new Promise((res,rej)=>{const fr=new FileReader();fr.onload=()=>res(fr.result);fr.onerror=rej;fr.readAsDataURL(blob)})}
async function makePhoto(file){const img=await fileToImage(file);const W=800,H=540,c=document.createElement('canvas');c.width=W;c.height=H;const ctx=c.getContext('2d');ctx.fillStyle='#ecfdf5';ctx.fillRect(0,0,W,H);const scale=Math.max(W/img.naturalWidth,H/img.naturalHeight),sw=W/scale,sh=H/scale,sx=(img.naturalWidth-sw)/2,sy=(img.naturalHeight-sh)/2;ctx.drawImage(img,Math.max(0,sx),Math.max(0,sy),Math.min(img.naturalWidth,sw),Math.min(img.naturalHeight,sh),0,0,W,H);return await new Promise(res=>c.toBlob(res,'image/jpeg',0.88))}
async function makeQr(file){const img=await fileToImage(file);const W=900,H=900,c=document.createElement('canvas');c.width=W;c.height=H;const ctx=c.getContext('2d');ctx.fillStyle='#fff';ctx.fillRect(0,0,W,H);const pad=54,box=W-pad*2,scale=Math.min(box/img.naturalWidth,box/img.naturalHeight),dw=img.naturalWidth*scale,dh=img.naturalHeight*scale;ctx.drawImage(img,(W-dw)/2,(H-dh)/2,dw,dh);return await new Promise(res=>c.toBlob(res,'image/png'))}
async function preview(member){const f=$(member.input)?.files?.[0];if(!f)return;const blob=await makePhoto(f);const data=await blobToDataUrl(blob);localStorage.setItem('doit-team-photo-'+member.key+'-dataurl',data);const img=$(member.preview);if(img)img.src=data}
async function previewQr(){const f=$('#devQrFile')?.files?.[0];if(!f)return;const blob=await makeQr(f);const data=await blobToDataUrl(blob);localStorage.setItem('doit-dev-qr-preview',data);const img=$('#devQrPreview');if(img)img.src=data}
async function upload(){try{const c=cfg();const chosen=TEAM.filter(m=>$(m.input)?.files?.[0]);if(!chosen.length)throw Error('ยังไม่ได้เลือกรูปทีมพัฒนา');status('กำลังปรับขนาดและอัปโหลดรูป...');const uploaded=[];for(const m of chosen){const file=$(m.input).files[0];const blob=await makePhoto(file);const data=await blobToDataUrl(blob);localStorage.setItem('doit-team-photo-'+m.key+'-dataurl',data);const img=$(m.preview);if(img)img.src=data;if(!c.k)throw Error('ยังไม่ได้ใส่ Supabase anon key จึงบันทึกได้เฉพาะเครื่องนี้ แต่ยังอัป Cloud ไม่ได้');await put(c,m.path,blob,'image/jpeg');uploaded.push(m.name)}const config={schema:'aya-team-config-v1',updated_at:new Date().toISOString(),members:TEAM.map(m=>({key:m.key,name:m.name,code:m.code,role:m.role,photo_url:publicUrl(c,m.path)}))};await put(c,'team/team-config.json',new Blob([JSON.stringify(config)],{type:'application/json;charset=utf-8'}),'application/json;charset=utf-8');localStorage.setItem('doit-team-config-v1',JSON.stringify(config));status('อัปโหลดรูปทีมพัฒนาแล้ว: '+uploaded.join(' / ')+'<br>หน้า Pro จะดึงรูปใหม่อัตโนมัติเมื่อเปิด popup ทีมพัฒนา',true)}catch(e){status('อัปโหลดรูปทีมพัฒนาไม่สำเร็จ: '+(e.message||e))}}
async function uploadQr(){try{const c=cfg();const f=$('#devQrFile')?.files?.[0];if(!f)throw Error('ยังไม่ได้เลือกรูป QR Code');if(!c.k)throw Error('ยังไม่ได้ใส่ Supabase anon key ในช่อง Cloud / Supabase');qrStatus('กำลังปรับขนาดและอัปโหลด QR Code...');const blob=await makeQr(f);await put(c,QR_PATH,blob,'image/png');const title=T($('#devQrTitle')?.value)||'QR Code';const note=T($('#devQrNote')?.value)||'สแกนเพื่อเปิดข้อมูลเพิ่มเติม';const config={schema:'aya-dev-qr-v1',enabled:true,title,note,image_url:publicUrl(c,QR_PATH)+'?t='+Date.now(),storage_path:QR_PATH,updated_at:new Date().toISOString()};await put(c,QR_CONFIG_PATH,new Blob([JSON.stringify(config)],{type:'application/json;charset=utf-8'}),'application/json;charset=utf-8');localStorage.setItem('doit-dev-qr-config-v1',JSON.stringify(config));const img=$('#devQrPreview');if(img)img.src=config.image_url;qrStatus('อัปโหลด QR Code แล้ว<br>หน้า Pro จะแสดง QR ใต้ทีมผู้พัฒนาเมื่อเปิด popup ทีมพัฒนา',true)}catch(e){qrStatus('อัปโหลด QR Code ไม่สำเร็จ: '+(e.message||e))}}
async function disableQr(){try{const c=cfg();if(!c.k)throw Error('ยังไม่ได้ใส่ Supabase anon key ในช่อง Cloud / Supabase');const config={schema:'aya-dev-qr-v1',enabled:false,updated_at:new Date().toISOString()};await put(c,QR_CONFIG_PATH,new Blob([JSON.stringify(config)],{type:'application/json;charset=utf-8'}),'application/json;charset=utf-8');localStorage.setItem('doit-dev-qr-config-v1',JSON.stringify(config));qrStatus('ปิดการแสดง QR Code ในหน้า Pro แล้ว',true)}catch(e){qrStatus('ปิด QR ไม่สำเร็จ: '+(e.message||e))}}
function injectQrCard(){if($('#devQrAdminCard'))return;const anchor=$('#teamPhotoStatus')?.closest('.card')||$('#uploadTeamPhotos')?.closest('.card');if(!anchor)return;anchor.insertAdjacentHTML('afterend',`<section class="card" id="devQrAdminCard"><h3>อัปโหลด QR Code ใต้ทีมผู้พัฒนา</h3><p class="muted">QR Code นี้จะแสดงด้านล่างสุดใน popup ทีมผู้พัฒนาของหน้า Pro</p><div class="grid"><div class="field"><label>หัวข้อ QR</label><input id="devQrTitle" value="QR Code" placeholder="เช่น QR Code ติดต่อ / QR Code กลุ่มไลน์"></div><div class="field"><label>คำอธิบาย</label><input id="devQrNote" value="สแกนเพื่อเปิดข้อมูลเพิ่มเติม" placeholder="ข้อความใต้ QR"></div></div><div class="teamBox" style="margin-top:12px"><h4>เลือกรูป QR Code</h4><input id="devQrFile" class="teamFile" type="file" accept="image/png,image/jpeg,image/jpg,image/webp"><img id="devQrPreview" class="teamPreview" alt="Preview QR Code" style="height:220px;object-fit:contain;background:#fff"></div><div class="row" style="margin-top:12px"><button class="btn" id="uploadDevQr">อัปโหลด QR Code</button><button class="btn2 danger" id="disableDevQr">ปิดการแสดง QR</button><button class="btn2" id="openProAfterQr">เปิดหน้า Pro เพื่อตรวจ</button></div><div id="devQrStatus" class="muted" style="margin-top:10px">ยังไม่ได้เลือกรูป QR Code</div></section>`);const old=localStorage.getItem('doit-dev-qr-preview');if(old&&$('#devQrPreview'))$('#devQrPreview').src=old;$('#devQrFile')?.addEventListener('change',()=>previewQr().catch(e=>qrStatus(e.message||e)));$('#uploadDevQr').onclick=uploadQr;$('#disableDevQr').onclick=disableQr;$('#openProAfterQr').onclick=()=>location.href='/pro.html?v=19&t='+Date.now()}
function patchLabels(){const h=[...document.querySelectorAll('.teamBox h4')].find(x=>T(x.textContent)==='ฐากูร อุปมัย');if(h)h.textContent='นาย ฐากูร อุปมัย';const img=$('#teamThakoonPreview');if(img)img.alt='Preview นาย ฐากูร'}
function bind(){patchLabels();TEAM.forEach(m=>{$(m.input)?.addEventListener('change',()=>preview(m).catch(e=>status(e.message||e)));const data=localStorage.getItem('doit-team-photo-'+m.key+'-dataurl');if(data&&$(m.preview))$(m.preview).src=data});const b=$('#uploadTeamPhotos');if(b)b.onclick=upload;const p=$('#openProAfterTeam');if(p)p.onclick=()=>location.href='/pro.html?v=19&t='+Date.now();injectQrCard()}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',bind);else bind();
})();
